ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?library2 ?shelving_space WHERE {
  ?library a :Libraries .
  ?library p:Library ?library2 .
  ?library p:Shelving_Space ?shelving_space .
  ?library p:Accessible ?accessible_f .
  FILTER(STR(?accessible_f) = STR("Yes"))
} }
  full: { SELECT ?library2 ?number_of_volumes ?shelving_space WHERE {
  ?library a :Libraries .
  ?library p:Library ?library2 .
  ?library p:Number_Of_Volumes ?number_of_volumes .
  ?library p:Shelving_Space ?shelving_space .
  ?library p:Accessible ?accessible_f .
  FILTER(STR(?accessible_f) = STR("Yes"))
} }
  component_2: { SELECT ?library2 ?number_of_volumes WHERE {
  ?library a :Libraries .
  ?library p:Library ?library2 .
  ?library p:Number_Of_Volumes ?number_of_volumes .
  ?library p:Accessible ?accessible_f .
  FILTER(STR(?accessible_f) = STR("Yes"))
} }
}

